def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / (bin_cap + 1e-9)
        priority = 0.0
        if ratio > 7:
            for a in range(7, 2, -2):
                for b in range(a, a + 4):
                    for c in range(1, 4):
                        term = ((ratio - a) ** 6) / (a * b * (c + 0.7))
                        trig = np.cos(ratio * b / (c + 1)) + np.sin(ratio * c / (b + 1))
                        priority += term * trig ** 2
            priority += np.exp(ratio - 7) * (np.sin(ratio * 1.3) + np.cos(ratio * 0.8)) ** 2.1
        elif 4 <= ratio <= 7:
            sum_p = 0.0
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 5):
                    val = ((ratio - p) ** 4) * np.sin(ratio * q) / (q + 1)
                    sum_p += np.tanh(val) * 1.5
            priority = sum_p + np.log1p(ratio) * 12 - np.tanh(ratio - 4) * 3
            if bin_cap > item * 5:
                priority -= np.exp(-ratio) * 5
            else:
                priority += np.log(bin_cap + 1) * 2
        elif 2 <= ratio < 4:
            s1, s2 = 0, 0
            for r in range(1, 15):
                s1 += ((ratio - 2) ** r) / (r * 1.9) * np.cos(r * ratio * 1.2)
            for r in range(1, 7):
                s2 += ((4 - ratio) ** r) / (r + 0.5) * np.sin(r * ratio * 0.9)
            priority = s1 * np.cos(9 * ratio) - np.log1p(ratio) * 8 + np.tanh(3 * (4 - ratio)) * 2.2 + s2 * 0.5
        elif 1 <= ratio < 2:
            penalty = 0
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3.1
            s = 0
            for n in range(1, 14):
                s += ((2 - ratio) ** n) / (n ** 2 + 1)
            priority = s + penalty + np.exp(-2 / (ratio + 0.02))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.2) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.4 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.8)
            if ((i * 2 + int(item * 2)) % 5) == 1:
                priority = s * np.log1p(bin_cap + 4) * 1.7
            else:
                priority = s / (np.sqrt(bin_cap + 2) + 3.5)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.4) * 0.9
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 15):
                s += ((0.4 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 2:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.8) * 4
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 3:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.2) * 5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 7.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 6
        for idxd in range(1, 6):
            if (i + idxd * 2) % 4 == 1:
                priority += np.sin(ratio * (i + idxd) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idxd) * 1.1) * 0.4
        if i % 4 == 1:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        for w in range(1, 3):
            priority += np.tanh(np.sin(ratio * i * w)) * (w + 0.2)
        if ratio < 1 and bin_cap > item * 0.7:
            priority += np.exp(-0.5 * (item - bin_cap)) * 3
        priorities[i] = priority
    return priorities
